func:
if (global.get('pgPool') && global.get('influxWrite')) {
  node.status({ fill: 'green', shape: 'dot', text: 'pool+influx ok' });
  return null;
}

// --- PostgreSQL ---
if (!global.get('pgPool')) {
  const { Pool } = pg;
  const pool = new Pool({
    host: env.get('POSTGRES_HOST') || 'postgres',
    port: parseInt(env.get('POSTGRES_PORT') || '5432'),
    user: env.get('POSTGRES_USER'),
    password: env.get('POSTGRES_PASSWORD'),
    database: env.get('POSTGRES_DB'),
    max: 10,
    idleTimeoutMillis: 30000
  });
  try {
    await pool.query('SELECT 1');
    global.set('pgPool', pool);
  } catch (e) {
    node.error('PG pool: ' + e.message);
    node.status({ fill: 'red', shape: 'ring', text: 'pg: ' + e.message.slice(0, 30) });
    return null;
  }
}

// --- InfluxDB ---
if (!global.get('influxWrite')) {
  const { InfluxDB, Point } = Influx;
  const client = new InfluxDB({
    url: env.get('INFLUXDB_URL') || 'http://influxdb:8086',
    token: env.get('INFLUX_ADMIN_TOKEN')
  });
  const writeApi = client.getWriteApi(
    env.get('INFLUX_ORG'),
    env.get('INFLUX_BUCKET'),
    'ns',
    { flushInterval: 2000, batchSize: 100 }
  );
  global.set('influxWrite', writeApi);
  global.set('influxPoint', Point);
}

node.status({ fill: 'green', shape: 'dot', text: 'pool+influx OK ' + new Date().toISOString().slice(11, 19) });
return null;

// E2.2 + E2.2.1 + E3.x — validação do envelope (com fallback flat) + presence event
const MAX = parseInt(env.get('MQTT_MAX_PAYLOAD_BYTES') || '4096');
const pool = global.get('pgPool');
const writeApi = global.get('influxWrite');
const Point = global.get('influxPoint');
if (!pool) { node.status({ fill:'red', shape:'ring', text:'sem pool' }); return null; }

const topic = msg.topic || '';
const parts = topic.split('/');
if (parts.length !== 3 || parts[0] !== 'devices' || parts[2] !== 'data') {
  node.warn('topic invalido: ' + topic); return null;
}
const mqttUser = parts[1];
if (!mqttUser || mqttUser.length > 64) { node.warn('serial invalido'); return null; }

let raw = msg.payload;
let str;
if (Buffer.isBuffer(raw)) str = raw.toString('utf8');
else if (typeof raw === 'string') str = raw;
else if (raw && typeof raw === 'object') str = JSON.stringify(raw);
else { node.warn('payload type inesperado: ' + typeof raw); return null; }
if (str.length > MAX) { node.warn('payload > ' + MAX + 'B'); return null; }

let env_;
try { env_ = JSON.parse(str); } catch (e) { node.warn('JSON invalido: ' + e.message); return null; }
if (!env_ || typeof env_ !== 'object' || Array.isArray(env_)) { node.warn('envelope nao e objeto'); return null; }

// E3.x — aceita envelope { ts, readings } OU payload flat. Firmware novo do
// INT-V2 publica flat ({umidade_solo:62.9, uptime_s:371, ...}); ingest
// deve aceitar ambos pra não quebrar devices legitimamente associados.
let tsNum;
let readings;
if (typeof env_.ts === 'number' && Number.isFinite(env_.ts) && env_.ts > 0 &&
    env_.readings && typeof env_.readings === 'object' && !Array.isArray(env_.readings)) {
  tsNum = env_.ts;
  readings = env_.readings;
} else {
  tsNum = Date.now();
  readings = {};
  for (const k of Object.keys(env_)) {
    const v = env_[k];
    if (typeof v === 'number' && Number.isFinite(v)) readings[k] = v;
  }
}

const keys = Object.keys(readings);
if (keys.length === 0) { node.warn('nenhum campo numerico no payload'); return null; }
for (const k of keys) {
  if (typeof k !== 'string' || k.length === 0 || k.length > 32) { node.warn('key invalida: ' + k); return null; }
  const v = readings[k];
  if (typeof v !== 'number' || !Number.isFinite(v)) { node.warn('valor nao numerico em ' + k); return null; }
}

const tsMs = tsNum < 1e12 ? tsNum * 1000 : tsNum;
const tsIso = new Date(tsMs).toISOString();

try {
  const r = await pool.query(
    'SELECT id, user_id, status, is_online FROM devices WHERE mqtt_username=$1 LIMIT 1',
    [mqttUser]
  );
  if (r.rowCount === 0) {
    await pool.query('INSERT INTO mqtt_events(topic,client_id,payload) VALUES($1,$2,$3)',
      [topic, mqttUser, JSON.stringify(env_)]);
    node.status({ fill:'yellow', shape:'ring', text: mqttUser + ' nao cadastrado' });
    return null;
  }
  const dev = r.rows[0];
  // E3.1: 'associado' é o novo 'active'. Aceita ambos por retrocompatibilidade.
  if (dev.status !== 'associado' && dev.status !== 'active') {
    node.status({ fill:'yellow', shape:'ring', text: mqttUser + ' status=' + dev.status });
    return null;
  }
  const devId = dev.id;
  const wasOnline = dev.is_online === true;
  const readingsJson = JSON.stringify(readings);

  await pool.query(
    'INSERT INTO device_readings(device_id, ts, topic, payload) VALUES($1,$2,$3,$4::jsonb)',
    [devId, tsIso, topic, readingsJson]
  );
  await pool.query(
    'UPDATE devices SET last_reading=$1::jsonb, last_reading_at=$2, last_seen=NOW(), is_online=TRUE WHERE id=$3',
    [readingsJson, tsIso, devId]
  );

  let fieldCount = 0;
  if (writeApi && Point) {
    const p = new Point('readings').tag('device_id', devId).tag('mqtt_user', mqttUser).timestamp(new Date(tsMs));
    for (const k of keys) { p.floatField(k, readings[k]); fieldCount++; }
    if (fieldCount > 0) writeApi.writePoint(p);
  }

  node.status({ fill:'green', shape:'dot', text: mqttUser + ' pg+ifx('+fieldCount+'f) '+new Date().toISOString().slice(11,19) });
  msg.saved = { device_id: devId, ts: tsIso, readings: readings, influx_fields: fieldCount };

  let presenceMsg = null;
  if (!wasOnline) {
    presenceMsg = {
      topic: 'devices/' + mqttUser + '/status',
      payload: JSON.stringify({
        type: 'device_status_changed',
        online: true,
        device_id: devId,
        serial: mqttUser,
        user_id: dev.user_id,
        last_seen_at: new Date().toISOString(),
        source: 'ingest'
      })
    };
  }
  return [msg, presenceMsg];
} catch (e) {
  node.error('ingest: ' + e.message, msg);
  return null;
}

// E2.2.1 — status estrito: 'online' -> true, qq outra coisa -> false.
// Ignora payloads que sejam objetos/JSON (são eventos publicados pela
// própria plataforma → evita loop que flipa is_online=false logo após o
// ingest flipar pra true).
// Publica device_status_changed apenas se houve transição real.
const pool = global.get('pgPool');
if (!pool) return null;
const parts = (msg.topic || '').split('/');
if (parts.length !== 3) return null;
const mqttUser = parts[1];
if (!mqttUser || mqttUser.length > 64) return null;
// Skip self-published presence events. O mqtt in com datatype=auto-detect
// parseia JSON → msg.payload vira objeto; String(obj) dá '[object Object]',
// então não basta checar startsWith('{').
if (msg.payload && typeof msg.payload === 'object') return null;
const raw = Buffer.isBuffer(msg.payload) ? msg.payload.toString('utf8') : String(msg.payload || '');
const trimmed = raw.trim();
if (trimmed.startsWith('{') || trimmed.startsWith('[')) return null;
const online = trimmed.toLowerCase() === 'online';
try {
  const sel = await pool.query(
    'SELECT id, user_id, is_online, last_seen FROM devices WHERE mqtt_username=$1 LIMIT 1',
    [mqttUser]
  );
  if (sel.rowCount === 0) return null;
  const dev = sel.rows[0];
  const wasOnline = dev.is_online === true;
  // Atualiza last_seen só quando online=true; offline preserva o timestamp
  // da última vez que realmente vimos dado (importante pro sweeper).
  if (online) {
    await pool.query(
      'UPDATE devices SET is_online=TRUE, last_seen=NOW() WHERE mqtt_username=$1',
      [mqttUser]
    );
  } else {
    await pool.query(
      'UPDATE devices SET is_online=FALSE WHERE mqtt_username=$1',
      [mqttUser]
    );
  }
  node.status({ fill: online ? 'green' : 'red', shape: 'dot', text: mqttUser + ' ' + (online ? 'on' : 'off') });
  if (wasOnline === online) return null; // sem transição
  const presence = {
    topic: 'devices/' + mqttUser + '/status',
    payload: JSON.stringify({
      type: 'device_status_changed',
      online: online,
      device_id: dev.id,
      serial: mqttUser,
      user_id: dev.user_id,
      last_seen_at: online ? new Date().toISOString() : (dev.last_seen ? new Date(dev.last_seen).toISOString() : null),
      source: 'status-mirror'
    })
  };
  return [null, presence];
} catch (e) { node.warn('status update: ' + e.message); }
return null;

const pool = global.get('pgPool');
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return msg; }
const body = msg.payload || {};
const email = (body.email||'').toLowerCase().trim();
const password = body.password||'';
if (!email || !password) { msg.statusCode=400; msg.payload={error:'missing credentials'}; return msg; }
try {
  const r = await pool.query('SELECT id,email,password_hash,full_name,role,is_active,email_verified FROM app_users WHERE email=$1',[email]);
  if (r.rowCount===0) { msg.statusCode=401; msg.payload={error:'invalid credentials'}; return msg; }
  const u = r.rows[0];
  if (!u.is_active) { msg.statusCode=403; msg.payload={error:'user inactive'}; return msg; }
  if (!u.email_verified) { msg.statusCode=403; msg.payload={error:'email_not_verified'}; return msg; }
  const ok = await bcrypt.compare(password, u.password_hash);
  if (!ok) { msg.statusCode=401; msg.payload={error:'invalid credentials'}; return msg; }
  const secret = env.get('JWT_SECRET');
  const access = jwt.sign({sub:u.id,email:u.email,role:u.role,name:u.full_name}, secret, {expiresIn:'15m'});
  const refresh = jwt.sign({sub:u.id,typ:'refresh'}, secret, {expiresIn:'7d'});
  msg.statusCode=200;
  msg.payload={access_token:access, refresh_token:refresh, expires_in:900, user:{id:u.id,email:u.email,name:u.full_name,role:u.role}};
} catch(e) {
  node.error('login: '+e.message, msg);
  msg.statusCode=500; msg.payload={error:'internal'};
}
return msg;

const auth = (msg.req.headers['authorization']||'').trim();
const m = auth.match(/^Bearer (.+)$/);
if (!m) { msg.statusCode=401; msg.payload={error:'missing bearer token'}; return msg; }
try {
  const secret = env.get('JWT_SECRET');
  const decoded = jwt.verify(m[1], secret);
  if (decoded.typ === 'refresh') { msg.statusCode=401; msg.payload={error:'refresh token cannot be used here'}; return msg; }
  msg.statusCode=200;
  msg.payload = {
    host: 'hub.xtconect.online',
    port: 8884,
    protocol: 'wss',
    path: '/mqtt',
    username: 'webapp',
    password: env.get('MQTT_WEB_PASSWORD'),
    client_id_prefix: 'webapp-'+String(decoded.sub).substring(0,8),
    keepalive: 60
  };
} catch(e) {
  msg.statusCode=401; msg.payload={error:'invalid token', detail:e.message};
}
return msg;

const pool = global.get('pgPool');
let pgOk = false;
try { if (pool) { const r = await pool.query('SELECT 1 as ok'); pgOk = r.rows[0].ok === 1; } } catch(e){}
msg.statusCode=200;
msg.payload={status:'ok', services:{postgres:pgOk, node_red:true}, ts:new Date().toISOString()};
return msg;

const pool = global.get('pgPool');
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return msg; }
const body = msg.payload || {};
const refreshToken = body.refresh_token;
if (!refreshToken) { msg.statusCode=400; msg.payload={error:'missing refresh token'}; return msg; }
const secret = env.get('JWT_SECRET');
let decoded;
try { decoded = jwt.verify(refreshToken, secret); }
catch(e) { msg.statusCode=401; msg.payload={error:'invalid refresh token'}; return msg; }
if (decoded.typ !== 'refresh') { msg.statusCode=401; msg.payload={error:'invalid refresh token'}; return msg; }
try {
  const r = await pool.query('SELECT id,email,full_name,role,is_active FROM app_users WHERE id=$1',[decoded.sub]);
  if (r.rowCount===0 || !r.rows[0].is_active) { msg.statusCode=401; msg.payload={error:'user inactive'}; return msg; }
  const u = r.rows[0];
  const access = jwt.sign({sub:u.id,email:u.email,role:u.role,name:u.full_name}, secret, {expiresIn:'15m'});
  msg.statusCode=200;
  msg.payload={access_token:access, expires_in:900};
} catch(e) {
  node.error('refresh: '+e.message, msg);
  msg.statusCode=500; msg.payload={error:'internal'};
}
return msg;

const auth = (msg.req.headers['authorization']||'').trim();
const m = auth.match(/^Bearer (.+)$/);
if (!m) { msg.statusCode=401; msg.payload={error:'missing bearer token'}; return [null, msg]; }
try {
  const secret = env.get('JWT_SECRET');
  const decoded = jwt.verify(m[1], secret);
  if (decoded.typ === 'refresh') { msg.statusCode=401; msg.payload={error:'refresh token cannot be used here'}; return [null, msg]; }
  msg.user = { id: decoded.sub, email: decoded.email, role: decoded.role };
  return [msg, null];
} catch(e) {
  msg.statusCode=401; msg.payload={error:'invalid token'}; return [null, msg];
}

// E3.5 — lista do user logado, com apelido opcional.
const pool = global.get('pgPool');
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return msg; }
const userId = msg.user && msg.user.id;
if (!userId) { msg.statusCode=401; msg.payload={error:'unauthenticated'}; return msg; }
try {
  const r = await pool.query(`
    SELECT
      v.id,
      COALESCE(NULLIF(v.nome_amigavel, ''), v.name) AS nome,
      v.apelido,
      v.device_id AS serial,
      m.nome AS modelo,
      uv.recebido_em AS ultimo_valor,
      v.created_at AS criado_em,
      v.is_online AS online,
      v.last_seen AS last_seen_at,
      v.telemetry_interval_s,
      v.burst_rate_s,
      v.access_type,
      v.permissao::text AS permissao,
      v.share_id
    FROM dispositivos_visiveis v
    LEFT JOIN modelos_dispositivo m ON m.id = v.modelo_id
    LEFT JOIN LATERAL (
      SELECT recebido_em FROM dispositivo_ultimo_valor
      WHERE dispositivo_id = v.id ORDER BY recebido_em DESC LIMIT 1
    ) uv ON TRUE
    WHERE v.viewer_id = $1::uuid
    ORDER BY v.created_at DESC
  `, [userId]);
  msg.statusCode = 200;
  msg.payload = r.rows;
} catch(e) {
  node.error('list dispositivos: '+e.message, msg);
  msg.statusCode = 500; msg.payload = {error:'internal'};
}
return msg;

const auth = (msg.req.headers['authorization']||'').trim();
const m = auth.match(/^Bearer (.+)$/);
if (!m) { msg.statusCode=401; msg.payload={error:'missing bearer token'}; return [null, msg]; }
try {
  const secret = env.get('JWT_SECRET');
  const decoded = jwt.verify(m[1], secret);
  if (decoded.typ === 'refresh') { msg.statusCode=401; msg.payload={error:'refresh token cannot be used here'}; return [null, msg]; }
  msg.user = { id: decoded.sub, email: decoded.email, role: decoded.role, name: decoded.name };
  return [msg, null];
} catch(e) {
  msg.statusCode=401; msg.payload={error:'invalid token'}; return [null, msg];
}

const pool = global.get('pgPool');
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return msg; }
const sql = `
  SELECT
    m.id, m.nome, m.descricao, m.fabricante, m.criado_em,
    m.prefixo, m.major_version, m.rate_default_segundos, m.ativo,
    (SELECT COUNT(*)::int FROM devices d WHERE d.modelo_id = m.id) AS total_dispositivos
  FROM modelos_dispositivo m
  WHERE m.ativo = TRUE
  ORDER BY m.nome ASC
`;
try {
  const r = await pool.query(sql);
  msg.statusCode = 200;
  msg.payload = r.rows;
} catch(e) {
  node.error('list modelos: '+e.message, msg);
  msg.statusCode = 500; msg.payload = {error:'internal'};
}
return msg;

const auth = (msg.req.headers['authorization']||'').trim();
const m = auth.match(/^Bearer (.+)$/);
if (!m) { msg.statusCode=401; msg.payload={error:'missing bearer token'}; return [null, msg]; }
try {
  const secret = env.get('JWT_SECRET');
  const decoded = jwt.verify(m[1], secret);
  if (decoded.typ === 'refresh') { msg.statusCode=401; msg.payload={error:'refresh token cannot be used here'}; return [null, msg]; }
  msg.user = { id: decoded.sub, email: decoded.email, role: decoded.role, name: decoded.name };
  return [msg, null];
} catch(e) {
  msg.statusCode=401; msg.payload={error:'invalid token'}; return [null, msg];
}

if (!msg.user || msg.user.role !== 'admin') {
  msg.statusCode=403; msg.payload={error:'forbidden'};
  return [null, msg];
}
return [msg, null];

const pool = global.get('pgPool');
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return msg; }
const id = msg.req.params.id;
if (!/^[0-9a-f-]{36}$/i.test(id)) { msg.statusCode=400; msg.payload={error:'invalid id'}; return msg; }
try {
  const r = await pool.query('SELECT id,nome,descricao,fabricante,imagem_url,especificacoes,protocolos_suportados,retencao_historico_horas,ativo,criado_em,atualizado_em,prefixo,major_version,rate_default_segundos FROM modelos_dispositivo WHERE id=$1',[id]);
  if (r.rowCount===0) { msg.statusCode=404; msg.payload={error:'not found'}; return msg; }
  const modelo = r.rows[0];
  const w = await pool.query(`
    SELECT mw.id, mw.widget_id AS catalogo_widget_id, mw.titulo, mw.ordem,
           mw.coluna, mw.linha, mw.largura, mw.altura,
           mw.direcao, mw.json_path_leitura, mw.nome_comando,
           mw.configuracao AS config_padrao, mw.ativo,
           cw.nome AS widget_nome, cw.tipo AS widget_tipo, cw.icone AS widget_icone
    FROM modelo_widgets mw
    JOIN catalogo_widgets cw ON cw.id = mw.widget_id
    WHERE mw.modelo_id = $1 AND mw.ativo = TRUE
    ORDER BY mw.ordem ASC
  `, [id]);
  modelo.widgets = w.rows;
  msg.statusCode = 200;
  msg.payload = modelo;
} catch(e) {
  node.error('get modelo: '+e.message, msg);
  msg.statusCode = 500; msg.payload = {error:'internal'};
}
return msg;

const auth = (msg.req.headers['authorization']||'').trim();
const m = auth.match(/^Bearer (.+)$/);
if (!m) { msg.statusCode=401; msg.payload={error:'missing bearer token'}; return [null, msg]; }
try {
  const secret = env.get('JWT_SECRET');
