}

if (!msg.user || msg.user.role !== 'admin') {
  msg.statusCode=403; msg.payload={error:'forbidden'};
  return [null, msg];
}
return [msg, null];

const pool = global.get('pgPool');
if (!pool) { msg.statusCode=503; msg.payload={error:'db not ready'}; return msg; }
const body = msg.payload || {};
const nome = (body.nome||'').trim();
const fabricante = (body.fabricante||'').trim();
const descricao = body.descricao || null;
const widgets = Array.isArray(body.widgets) ? body.widgets : [];
if (!nome) { msg.statusCode=400; msg.payload={error:'nome obrigatorio'}; return msg; }
if (!fabricante) { msg.statusCode=400; msg.payload={error:'fabricante obrigatorio'}; return msg; }
const ENVIAR = new Set(['botao','slider','campo_texto','switch_personalizado']);
const BIDIR = new Set(['switch']);
async function insertWidgets(client, modeloId, widgets) {
  for (let i=0; i<widgets.length; i++) {
    const w = widgets[i] || {};
    const widgetId = w.catalogo_widget_id;
    if (!widgetId) continue;
    const cw = await client.query('SELECT nome, tipo, configuracao_padrao FROM catalogo_widgets WHERE id=$1',[widgetId]);
    if (cw.rowCount===0) throw new Error('widget nao encontrado: '+widgetId);
    const tipo = cw.rows[0].tipo;
    let direcao = 'receber', jsonPath = tipo, nomeCmd = null;
    if (ENVIAR.has(tipo)) { direcao='enviar'; jsonPath=null; nomeCmd=tipo; }
    else if (BIDIR.has(tipo)) { direcao='bidirecional'; jsonPath=tipo; nomeCmd=tipo; }
    const config = (w.config_padrao && typeof w.config_padrao === 'object') ? w.config_padrao : cw.rows[0].configuracao_padrao;
    await client.query(
      'INSERT INTO modelo_widgets (modelo_id,widget_id,titulo,ordem,direcao,json_path_leitura,nome_comando,configuracao) VALUES ($1,$2,$3,$4,$5::direcao_dado,$6,$7,$8::jsonb)',
      [modeloId, widgetId, w.titulo || cw.rows[0].nome, (w.ordem != null ? w.ordem : i), direcao, jsonPath, nomeCmd, JSON.stringify(config)]
    );
  }
}
const client = await pool.connect();
try {
  await client.query('BEGIN');
  const r = await client.query(
    'INSERT INTO modelos_dispositivo (nome,fabricante,descricao,criado_por) VALUES ($1,$2,$3,$4) RETURNING id',
    [nome, fabricante, descricao, msg.user.id]
  );
  const modeloId = r.rows[0].id;
  await insertWidgets(client, modeloId, widgets);
  await client.query('COMMIT');
  msg.statusCode = 201;
  msg.payload = { id: modeloId };
} catch(e) {
  try { await client.query('ROLLBACK'); } catch(_) {}
  if (/unique/i.test(e.message) || /duplicate/i.test(e.message)) {
    msg.statusCode=409; msg.payload={error:'nome ja existe'};
  } else {
    node.error('create modelo: '+e.message, msg);
    msg.statusCode=500; msg.payload={error:'internal', detail: e.message};
  }
} finally {
  client.release();
}
return msg;

