    else if (BIDIR.has(tipo)) { direcao='bidirecional'; jsonPath=tipo; nomeCmd=tipo; }
    const config = (w.config_padrao && typeof w.config_padrao === 'object') ? w.config_padrao : cw.rows[0].configuracao_padrao;
